package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.io.StringReader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVParserTest {

    private CSVParser parser;

    @BeforeEach
    public void setUp() {
        String csvData = "header1,header2\nvalue1,value2";
        CSVFormat format = CSVFormat.DEFAULT.withHeader();
        parser = new CSVParser(new StringReader(csvData), format);
    }

    @Test
    public void testGetRecordNumber_initialValue() {
        // Initially, recordNumber should be 0 before any records are parsed
        assertEquals(0L, parser.getRecordNumber());
    }

    @Test
    public void testGetRecordNumber_afterNextRecord() {
        parser.nextRecord();
        // After parsing one record, recordNumber should be 1
        assertEquals(1L, parser.getRecordNumber());
    }

    @Test
    public void testGetRecordNumber_afterMultipleNextRecords() {
        parser.nextRecord();
        parser.nextRecord();
        // After parsing two records, recordNumber should be 2
        assertEquals(2L, parser.getRecordNumber());
    }
}
